import java.util.*;

public class ClassInfo {
    private String className;
    private String packageName;
    private String role;

    public ClassInfo(String className, String packageName) {
        this.className = className;
        this.packageName = packageName;
        this.role = detectRole(className);
    }

    private String detectRole(String name) {
        // TODO: Return 'Controller' if ends with 'Controller',
        // 'Service' if ends with 'Service',
        // 'Repository' if ends with 'Repository',
        // 'Entity' if ends with 'Entity' or 'Model',
        // 'Configuration' if ends with 'Config',
        // 'Other' otherwise
        return "Other";
    }

    @Override
    public String toString() {
        return packageName + "." + className + " [" + role + "]";
    }
}

public class ApplicationScanner {
    private List<ClassInfo> classes;

    public ApplicationScanner(List<ClassInfo> classes) {
        this.classes = classes;
    }

    public Map<String, List<ClassInfo>> groupByRole() {
        // TODO: Group classes by their role
        return new LinkedHashMap<>();
    }
}

public class Main {
    public static void main(String[] args) {
        List<ClassInfo> appClasses = Arrays.asList(
            new ClassInfo("UserController", "com.app.controller"),
            new ClassInfo("ProductController", "com.app.controller"),
            new ClassInfo("UserService", "com.app.service"),
            new ClassInfo("UserRepository", "com.app.repository"),
            new ClassInfo("UserEntity", "com.app.model"),
            new ClassInfo("AppConfig", "com.app.config")
        );

        ApplicationScanner scanner = new ApplicationScanner(appClasses);
        Map<String, List<ClassInfo>> grouped = scanner.groupByRole();
        grouped.forEach((role, classList) -> {
            System.out.println(role + ":");
            classList.forEach(c -> System.out.println("  " + c));
        });
    }
}

import java.util.*;

public interface CommandLineRunner {
    void run(String... args) throws Exception;
}

public class UserStore {
    private List<String> users = new ArrayList<>();
    public void addUser(String user) { users.add(user); }
    public List<String> getUsers() { return Collections.unmodifiableList(users); }
}

public class DataSeeder implements CommandLineRunner {
    private UserStore userStore;

    public DataSeeder(UserStore store) {
        this.userStore = store;
    }

    @Override
    public void run(String... args) throws Exception {
        // TODO: Seed 3 default users: admin, alice, bob
        System.out.println("Data seeding complete.");
    }
}

public class StartupHealthCheck implements CommandLineRunner {
    @Override
    public void run(String... args) throws Exception {
        // TODO: Print health check messages for DB and Cache
    }
}

public class AppStartup {
    public void start(List<CommandLineRunner> runners, String... args) throws Exception {
        System.out.println("Application context loaded. Running startup tasks...");
        for (CommandLineRunner runner : runners) {
            runner.run(args);
        }
        System.out.println("All startup tasks completed.");
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        UserStore store = new UserStore();
        DataSeeder seeder = new DataSeeder(store);
        StartupHealthCheck healthCheck = new StartupHealthCheck();

        AppStartup startup = new AppStartup();
        startup.start(Arrays.asList(healthCheck, seeder), args);

        System.out.println("Users in store: " + store.getUsers());
    }
}
